from kivy.lang import Builderfrom kivymd.app import MDAppfrom database import search_entriesclass MainApp(MDApp):    def build(self):        return Builder.load_file("homescreen.kv")    def search_db(self, query):        search_result = search_entries(query)        search_list = self.root.ids.search_results        search_list.clear_widgets()        for entry in search_result:            list_item = OneLineListItem(text=entry[1], on_press=self.show_details(entry))            search_list.add_widget(list_item)    def show_details(self, entry):        def inner_function(instance):            details_screen = self.root.ids.screen_manager.get_screen("entry_details")            details_screen.ids.entry_content.text = entry[2]            self.root.ids.screen_manager.current = "entry_details"        return inner_functionif __name__ == "__main__":    MainApp().run()